CREATE PROCEDURE dbo.usp_ProcessEmployeeBonus
    @EmployeeID INT,
    @BonusAmount DECIMAL(18, 2)
AS
BEGIN
    SET NOCOUNT ON

    DECLARE @IsSuccess BIT = 0
    DECLARE @ErrMsg NVARCHAR(4000)

    -- Process bonus inside TRY/CATCH
    BEGIN TRY
        -- [DBG-PREVIEW] Would have executed:
        SELECT N'UPDATE to table dbo.Employees' AS [DBG_Action], Bonus + @BonusAmount AS [calculated-Bonus], GETDATE() AS [calculated-LastModified]
        FROM dbo.Employees
        WHERE EmployeeID = @EmployeeID;

        -- [DBG-PREVIEW] Would have executed:
        SELECT N'INSERT to table dbo.AuditLog' AS [DBG_Action], @EmployeeID AS [@EmployeeID], CONCAT('Bonus processed: $', @BonusAmount) AS [calculated-LogMessage], GETDATE() AS [calculated-CreatedDate];

        SET @IsSuccess = 1
        PRINT CONCAT(N'[DBG] @IsSuccess = ', CAST(@IsSuccess AS NVARCHAR(4000)));
    END TRY
